func formatMod(mod int) string {
	if mod > 0 {
		return fmt.Sprintf("+%d", mod)
	}
	return fmt.Sprintf("%d", mod)
}

func xpBarWidth(view *CharacterView) string {
	total := view.Character.TotalXP
	toNext := view.XPToNext
	if toNext == 0 {
		return "width: 100%"
	}
	threshold := total + toNext
	if threshold == 0 {
		return "width: 0%"
	}
	pct := total * 100 / threshold
	if pct > 100 {
		pct = 100
	}
	return fmt.Sprintf("width: %d%%", pct)
}

